from __future__ import annotations

import base64
import hashlib
import re
import secrets
import sqlite3
from datetime import datetime, timedelta, timezone
from pathlib import Path
from typing import Any

import streamlit as st
import streamlit.components.v1 as components


APP_DIR = Path(__file__).parent
DB_PATH = APP_DIR / "scores.sqlite3"
FRONTEND_DIR = APP_DIR / "frontend"
FRONTEND_HTML_B64 = ""

# Streamlit Cloud potrafi wyrzucić błąd, gdy folder komponentu nie istnieje.
# Dlatego app.py tworzy komponent sam przy starcie.
FRONTEND_DIR.mkdir(parents=True, exist_ok=True)
(FRONTEND_DIR / "index.html").write_text(
    base64.b64decode(FRONTEND_HTML_B64.encode("ascii")).decode("utf-8"),
    encoding="utf-8",
)

DEFAULT_SALT = "zmien-ten-sekret-w-streamlit-secrets"


st.set_page_config(
    page_title="Saperka vs Kurierzy+",
    page_icon="🪖",
    layout="wide",
    initial_sidebar_state="collapsed",
)

_game_component = components.declare_component(
    "saperka_game_plus",
    path=str(FRONTEND_DIR),
)


def now_iso() -> str:
    return datetime.now(timezone.utc).isoformat(timespec="seconds")


def get_secret_salt() -> str:
    try:
        return str(st.secrets.get("IP_HASH_SALT", DEFAULT_SALT))
    except Exception:
        return DEFAULT_SALT


def get_client_ip() -> str | None:
    """Zwraca IP połączenia, jeśli Streamlit je udostępnia.

    Uwaga: IP nie powinno być używane jako zabezpieczenie. Tu służy tylko
    do automatycznego przypisania nicku i rankingu.
    """
    try:
        ip = getattr(st.context, "ip_address", None)
        if ip:
            return str(ip)
    except Exception:
        pass

    try:
        headers = st.context.headers
        for key in ("cf-connecting-ip", "x-real-ip", "x-forwarded-for", "x-client-ip"):
            value = headers.get(key)
            if value:
                return str(value).split(",")[0].strip()
    except Exception:
        pass

    return None


def get_visitor_key() -> tuple[str, bool]:
    ip = get_client_ip()
    salt = get_secret_salt()

    if ip:
        digest = hashlib.sha256(f"{salt}:{ip}".encode("utf-8")).hexdigest()
        return digest, True

    # Fallback dla localhost/hostingu bez IP.
    # Nie utrzyma nicku między różnymi sesjami, ale pozwala testować.
    if "fallback_visitor_key" not in st.session_state:
        st.session_state.fallback_visitor_key = "session_" + secrets.token_hex(16)
    return st.session_state.fallback_visitor_key, False


def clean_nick(raw: str) -> str:
    nick = raw.strip()
    nick = re.sub(r"\s+", " ", nick)
    nick = re.sub(r"[^0-9A-Za-zĄĆĘŁŃÓŚŹŻąćęłńóśźż _-]", "", nick)
    return nick[:24]


def init_db() -> None:
    with sqlite3.connect(DB_PATH, timeout=30) as conn:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS players (
                visitor_key TEXT PRIMARY KEY,
                nick TEXT NOT NULL,
                created_at TEXT NOT NULL,
                updated_at TEXT NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS scores (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                visitor_key TEXT NOT NULL,
                nick TEXT NOT NULL,
                score INTEGER NOT NULL,
                round_id TEXT NOT NULL UNIQUE,
                max_combo INTEGER NOT NULL DEFAULT 0,
                boss_kills INTEGER NOT NULL DEFAULT 0,
                dpd_hits INTEGER NOT NULL DEFAULT 0,
                created_at TEXT NOT NULL
            )
            """
        )

        # Migracja dla osób, które miały starą bazę z poprzedniej wersji.
        cols = {row[1] for row in conn.execute("PRAGMA table_info(scores)").fetchall()}
        migrations = {
            "max_combo": "ALTER TABLE scores ADD COLUMN max_combo INTEGER NOT NULL DEFAULT 0",
            "boss_kills": "ALTER TABLE scores ADD COLUMN boss_kills INTEGER NOT NULL DEFAULT 0",
            "dpd_hits": "ALTER TABLE scores ADD COLUMN dpd_hits INTEGER NOT NULL DEFAULT 0",
        }
        for col, sql in migrations.items():
            if col not in cols:
                conn.execute(sql)

        conn.execute("CREATE INDEX IF NOT EXISTS idx_scores_score ON scores(score DESC)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_scores_visitor ON scores(visitor_key)")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_scores_created ON scores(created_at)")


def get_player_nick(visitor_key: str) -> str | None:
    with sqlite3.connect(DB_PATH, timeout=30) as conn:
        row = conn.execute(
            "SELECT nick FROM players WHERE visitor_key = ?",
            (visitor_key,),
        ).fetchone()
    return row[0] if row else None


def save_player_nick(visitor_key: str, nick: str) -> None:
    stamp = now_iso()
    with sqlite3.connect(DB_PATH, timeout=30) as conn:
        conn.execute(
            """
            INSERT INTO players(visitor_key, nick, created_at, updated_at)
            VALUES (?, ?, ?, ?)
            ON CONFLICT(visitor_key) DO UPDATE SET
                nick = excluded.nick,
                updated_at = excluded.updated_at
            """,
            (visitor_key, nick, stamp, stamp),
        )


def save_score(
    visitor_key: str,
    nick: str,
    score: int,
    round_id: str,
    max_combo: int,
    boss_kills: int,
    dpd_hits: int,
) -> bool:
    if not isinstance(score, int):
        return False
    if score < 0 or score > 999_999:
        return False
    if not round_id or len(round_id) > 80:
        return False

    max_combo = max(0, min(int(max_combo or 0), 9999))
    boss_kills = max(0, min(int(boss_kills or 0), 9999))
    dpd_hits = max(0, min(int(dpd_hits or 0), 9999))

    with sqlite3.connect(DB_PATH, timeout=30) as conn:
        try:
            conn.execute(
                """
                INSERT INTO scores(
                    visitor_key, nick, score, round_id,
                    max_combo, boss_kills, dpd_hits, created_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    visitor_key,
                    nick,
                    score,
                    round_id,
                    max_combo,
                    boss_kills,
                    dpd_hits,
                    now_iso(),
                ),
            )
            return True
        except sqlite3.IntegrityError:
            return False


def leaderboard(limit: int = 10, since: datetime | None = None) -> list[dict[str, Any]]:
    params: list[Any] = []
    where = ""
    if since is not None:
        where = "WHERE s.created_at >= ?"
        params.append(since.isoformat(timespec="seconds"))

    params.append(limit)

    with sqlite3.connect(DB_PATH, timeout=30) as conn:
        rows = conn.execute(
            f"""
            SELECT
                COALESCE(p.nick, s.nick) AS nick,
                MAX(s.score) AS best_score,
                MAX(s.max_combo) AS best_combo,
                MAX(s.boss_kills) AS best_bosses,
                MAX(s.dpd_hits) AS best_dpd_hits,
                COUNT(*) AS games_played,
                MAX(s.created_at) AS last_played
            FROM scores s
            LEFT JOIN players p ON p.visitor_key = s.visitor_key
            {where}
            GROUP BY s.visitor_key
            ORDER BY best_score DESC, last_played ASC
            LIMIT ?
            """,
            params,
        ).fetchall()

    return [
        {
            "place": idx + 1,
            "nick": row[0],
            "score": int(row[1] or 0),
            "max_combo": int(row[2] or 0),
            "boss_kills": int(row[3] or 0),
            "dpd_hits": int(row[4] or 0),
            "games": int(row[5] or 0),
            "last_played": row[6],
        }
        for idx, row in enumerate(rows)
    ]


def get_my_stats(visitor_key: str) -> dict[str, int]:
    with sqlite3.connect(DB_PATH, timeout=30) as conn:
        row = conn.execute(
            """
            SELECT
                MAX(score),
                MAX(max_combo),
                MAX(boss_kills),
                MAX(dpd_hits),
                COUNT(*)
            FROM scores
            WHERE visitor_key = ?
            """,
            (visitor_key,),
        ).fetchone()

    return {
        "best": int(row[0] or 0),
        "combo": int(row[1] or 0),
        "bosses": int(row[2] or 0),
        "dpd": int(row[3] or 0),
        "games": int(row[4] or 0),
    }


def render_css() -> None:
    st.markdown(
        """
        <style>
          .block-container {
            padding-top: 0.6rem;
            padding-bottom: 1rem;
            max-width: 1560px;
          }
          header, footer {
            visibility: hidden;
          }
          [data-testid="stMetric"] {
            background: rgba(255,255,255,0.04);
            border: 1px solid rgba(255,255,255,0.08);
            padding: 12px;
            border-radius: 14px;
          }
        </style>
        """,
        unsafe_allow_html=True,
    )


def main() -> None:
    render_css()
    init_db()

    visitor_key, has_ip = get_visitor_key()
    nick = get_player_nick(visitor_key)

    st.title("🪖 Saperka vs Kurierzy+")

    # Tu jest to, o co prosiłeś:
    # jeśli ktoś już wchodził z danego IP, nick zostanie przypisany automatycznie.
    if nick is None:
        st.info("Pierwsze wejście z tego IP. Podaj nick — potem będzie przypisywany automatycznie.")
        if not has_ip:
            st.warning(
                "Nie udało się odczytać IP w tym środowisku, więc aplikacja użyje tymczasowego ID sesji. "
                "Na Streamlit Cloud powinno działać lepiej niż lokalnie."
            )

        with st.form("nick_form", clear_on_submit=False):
            raw_nick = st.text_input("Nick", max_chars=24, placeholder="np. Michał")
            accepted = st.checkbox(
                "Rozumiem, że aplikacja zapisze nick, wynik, datę i hash mojego IP.",
                value=False,
            )
            submit = st.form_submit_button("Wejdź do gry")

        if submit:
            cleaned = clean_nick(raw_nick)
            if len(cleaned) < 3:
                st.error("Nick musi mieć minimum 3 znaki.")
            elif not accepted:
                st.error("Zaznacz zgodę na zapis wyniku w rankingu.")
            else:
                save_player_nick(visitor_key, cleaned)
                st.rerun()

        st.stop()

    my_stats = get_my_stats(visitor_key)
    now = datetime.now(timezone.utc)

    col1, col2, col3, col4, col5 = st.columns(5)
    col1.metric("Nick z IP", nick)
    col2.metric("Rekord", my_stats["best"])
    col3.metric("Max combo", my_stats["combo"])
    col4.metric("Bossy", my_stats["bosses"])
    col5.metric("Rundy", my_stats["games"])

    with st.expander("Zmień nick przypisany do tego IP"):
        st.caption("Po zmianie nick zostanie automatycznie użyty przy kolejnym wejściu z tego samego IP.")
        with st.form("change_nick_form", clear_on_submit=False):
            new_raw = st.text_input("Nowy nick", value=nick, max_chars=24)
            change = st.form_submit_button("Zapisz nowy nick")
        if change:
            new_nick = clean_nick(new_raw)
            if len(new_nick) < 3:
                st.error("Nick musi mieć minimum 3 znaki.")
            else:
                save_player_nick(visitor_key, new_nick)
                st.success("Nick zmieniony.")
                st.rerun()

    result = _game_component(
        nick=nick,
        leaderboard_all=leaderboard(10),
        leaderboard_daily=leaderboard(5, since=now - timedelta(days=1)),
        leaderboard_weekly=leaderboard(5, since=now - timedelta(days=7)),
        my_best=my_stats["best"],
        default=None,
        key="saperka_canvas_game_plus",
    )

    if isinstance(result, dict) and result.get("event") == "score":
        try:
            score = int(result.get("score", 0))
            max_combo = int(result.get("max_combo", 0))
            boss_kills = int(result.get("boss_kills", 0))
            dpd_hits = int(result.get("dpd_hits", 0))
        except Exception:
            score = 0
            max_combo = 0
            boss_kills = 0
            dpd_hits = 0

        round_id = str(result.get("round_id", ""))[:80]
        saved = save_score(
            visitor_key=visitor_key,
            nick=nick,
            score=score,
            round_id=round_id,
            max_combo=max_combo,
            boss_kills=boss_kills,
            dpd_hits=dpd_hits,
        )

        if saved:
            st.toast(f"Zapisano wynik: {score} pkt")
            st.rerun()

    st.caption(
        "Nick jest automatycznie przypisywany po hashu IP. Aplikacja nie zapisuje surowego IP. "
        "SQLite działa do prostego hostingu, ale do naprawdę trwałego rankingu najlepiej później "
        "podłączyć zewnętrzną bazę, np. Supabase/Neon/Postgres."
    )


if __name__ == "__main__":
    main()
